class Solution:
    def longestSubsequenceRepeatedK(self, s: str, k: int) -> str:
        from collections import Counter
        from itertools import permutations

        # Count frequency of each character in the string
        char_count = Counter(s)

        # Filter characters that can be part of the repeated subsequence at least k times
        valid_chars = [char for char, count in char_count.items() if count >= k]

        # Function to check if a subsequence can be repeated k times in s
        def is_valid_subsequence(subseq):
            subseq_k = subseq * k
            iterator = iter(s)
            return all(c in iterator for c in subseq_k)

        # Start with empty subsequence and try to build the longest valid one
        max_subseq = ""

        # Try subsequences of increasing length
        current_level = [""]
        while current_level:
            next_level = set()
            for subseq in current_level:
                for char in valid_chars:
                    new_subseq = subseq + char
                    if is_valid_subsequence(new_subseq):
                        next_level.add(new_subseq)
                        if len(new_subseq) > len(max_subseq) or (len(new_subseq) == len(max_subseq) and new_subseq > max_subseq):
                            max_subseq = new_subseq
            current_level = next_level

        return max_subseq
